// Freight Cost Calculator
// Reads form fields from the Ancroo extension and calculates shipping cost.

const input = $input.first().json;
const fields = input.fields || {};

const weight = parseFloat(fields.weight_kg) || 0;
const zone = (fields.zone || '').toUpperCase();
const packages = parseInt(fields.packages) || 1;

// Zone rates (EUR per kg)
const zoneRates = {
  'A': 2.50,   // Domestic
  'B': 4.00,   // EU
  'C': 7.50,   // International
  'D': 12.00   // Overseas
};

const rate = zoneRates[zone] || 5.00;  // Fallback rate
const totalCost = (weight * rate * packages).toFixed(2);

return [{ json: { freight_cost: totalCost } }];
